import argparse
import json
import logging
from pathlib import Path
import matplotlib.pyplot as plt
from easy_logging import EasyFormatter

handler = logging.StreamHandler()
handler.setFormatter(EasyFormatter())
logger = logging.getLogger(__name__)
logger.addHandler(handler)
logger.setLevel(logging.INFO)


def main() -> None:
    """Reads the evaluation_results.jsonl file generated by eval.py and creates two scatter plots."""
    parser = argparse.ArgumentParser(
        description="Visualize evaluation results from jsonl.",
    )
    parser.add_argument(
        "--eval_file_path",
        type=str,
        required=True,
        help="Path to the evaluation_results.jsonl file",
    )
    parser.add_argument(
        "--title",
        type=str,
        required=True,
        help="Custom title for the generated graphs",
    )
    args = parser.parse_args()

    eval_file = Path(args.eval_file_path)
    if not eval_file.exists():
        logger.info(f"Error: File not found at {eval_file}")
        return

    lengths = []
    redundancies = []
    sers = []

    # Parse the jsonl file
    with open(eval_file, encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue

            data = json.loads(line)

            # Skip the summary lines appended at the end of eval.py
            if "type" in data and data["type"].startswith("summary"):
                continue

            # Length can be safely derived from the plaintext
            length = len(data["plaintext"])
            redundancy = data["redundancy"]
            ser = data["ser"]

            lengths.append(length)
            redundancies.append(redundancy)
            sers.append(ser)

    if not sers:
        logger.info("No valid sample data found in the evaluation file.")
        return

    # Initialize plotting
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(14, 6))

    # Set the overarching title from the command line argument
    fig.suptitle(args.title, fontsize=16, fontweight="bold", y=1.05)

    # Graph 1: SER vs Length
    ax1.scatter(lengths, sers, alpha=0.5, color="#1f77b4", edgecolors="none")
    ax1.set_title("Symbol Error Rate (SER) vs Sequence Length")
    ax1.set_xlabel("Length (Characters)")
    ax1.set_ylabel("SER")
    ax1.grid(True, linestyle="--", alpha=0.6)

    # Graph 2: SER vs Redundancy
    ax2.scatter(redundancies, sers, alpha=0.5, color="#d62728", edgecolors="none")
    ax2.set_title("Symbol Error Rate (SER) vs Redundancy")
    ax2.set_xlabel("Redundancy")
    ax2.set_ylabel("SER")
    ax2.grid(True, linestyle="--", alpha=0.6)

    plt.tight_layout()

    # Save the output to the same directory as the evaluation file
    output_image_path = eval_file.with_name("evaluation_graphs.png")
    plt.savefig(output_image_path, dpi=300, bbox_inches="tight")
    logger.info(f"Graphs successfully generated and saved to:\n{output_image_path}")


if __name__ == "__main__":
    main()
